import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { SeedService } from '../../data/seed.service';
import { Task } from '../../data/models';

@Component({
  selector: 'app-tasks',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './tasks.component.html',
  styleUrl: './tasks.component.css',
})
export class TasksComponent {
  readonly views = ['daily', 'weekly', 'overdue'];
  activeView = signal('daily');

  // Local done-state keyed by task id (mockup; does not mutate seed).
  doneState = signal<Record<string, boolean>>({});

  private bucketForView(view: string): Task['bucket'] {
    switch (view) {
      case 'weekly': return 'week';
      case 'overdue': return 'overdue';
      default: return 'today';
    }
  }

  overdueCount = computed(() => this.seed.tasks().filter((t) => t.bucket === 'overdue').length);
  todayCount = computed(() => this.seed.tasks().filter((t) => t.bucket === 'today').length);
  weekCount = computed(() => this.seed.tasks().filter((t) => t.bucket === 'week').length);

  visibleTasks = computed<Task[]>(() => {
    const bucket = this.bucketForView(this.activeView());
    return this.seed.tasks().filter((t) => t.bucket === bucket);
  });

  signalTasks = computed<Task[]>(() => this.seed.tasks().filter((t) => t.source === 'signal'));

  isDone(id: string): boolean {
    return !!this.doneState()[id];
  }

  toggleDone(id: string): void {
    this.doneState.update((s) => ({ ...s, [id]: !s[id] }));
  }

  priorityBadge(priority: Task['priority']): string {
    switch (priority) {
      case 'high': return 'badge-danger';
      case 'medium': return 'badge-warning';
      case 'low': return 'badge-neutral';
      default: return 'badge-neutral';
    }
  }

  sourceBadge(source: Task['source']): string {
    switch (source) {
      case 'signal': return 'badge-info';
      case 'email': return 'badge-info';
      case 'reminder': return 'badge-neutral';
      case 'manual': return 'badge-neutral';
      default: return 'badge-neutral';
    }
  }

  setView(view: string): void {
    this.router.navigate([], { queryParams: { view }, queryParamsHandling: 'merge' });
  }

  noop(): void { /* mockup no-op */ }

  constructor(public seed: SeedService, private route: ActivatedRoute, private router: Router) {
    this.route.queryParamMap.subscribe((q) => {
      const v = q.get('view');
      this.activeView.set(v && this.views.includes(v) ? v : 'daily');
    });
  }
}
